protected void addChildren(int index, Node... children) {
    Validate.noNullElements(children);
    ensureChildNodes();

    // Check if any of the children are already children of this node
    // If so, we need to handle the reordering carefully to avoid index issues
    boolean containsSelfChildren = false;
    for (Node child : children) {
        if (child.parentNode == this) {
            containsSelfChildren = true;
            break;
        }
    }

    if (containsSelfChildren) {
        // Handle the case where some children are already our children
        // We need to remove them first, then add them back at the new position
        // To avoid index shifting issues, remove in reverse order by index
        int[] removeIndices = new int[children.length];
        boolean[] isSelfChild = new boolean[children.length];

        // Find the original indices for the children that are our own children
        for (int i = 0; i < children.length; i++) {
            if (children[i].parentNode == this) {
                removeIndices[i] = children[i].siblingIndex;
                isSelfChild[i] = true;
            } else {
                isSelfChild[i] = false;
            }
        }

        // Sort the self-children indices in descending order to remove them from right to left
        // This prevents index shifting during removal
        Integer[] selfIndices = new Integer[children.length];
        for (int i = 0; i < children.length; i++) {
            selfIndices[i] = isSelfChild[i] ? removeIndices[i] : -1;
        }

        // Remove self-children in reverse order (from rightmost to leftmost) to avoid index shifting
        for (int origIndex = 0; origIndex < children.length; origIndex++) {
            if (isSelfChild[origIndex]) {
                // Find the rightmost unprocessed self-child
                int maxIdx = -1;
                int maxOrigIdx = -1;
                for (int j = 0; j < children.length; j++) {
                    if (isSelfChild[j] && removeIndices[j] > maxIdx) {
                        maxIdx = removeIndices[j];
                        maxOrigIdx = j;
                    }
                }
                if (maxOrigIdx != -1) {
                    // Mark this as processed by setting it to -1
                    isSelfChild[maxOrigIdx] = false;
                    removeChild(children[maxOrigIdx]);
                }
            }
        }

        // Now add all children at the specified index
        for (int i = children.length - 1; i >= 0; i--) {
            Node in = children[i];
            if (in.parentNode != this) {  // Only reparent if not already removed above
                reparentChild(in);
            }
            childNodes.add(index, in);
        }
    } else {
        // Original logic for when no children are from this parent
        for (int i = children.length - 1; i >= 0; i--) {
            Node in = children[i];
            reparentChild(in);
            childNodes.add(index, in);
        }
    }
    reindexChildren(index);
}

